test_cases.assertion_pseudocode:
pkg = parseJSON(readFile('web/package.json'))
for version in pkg.dependencies.values():
  assert version.startsWith('^')
for version in pkg.devDependencies.values():
  assert version.startsWith('^')

requiredFiles = ['package.json','tsconfig.json','tsconfig.node.json','vite.config.ts','tailwind.config.ts','postcss.config.js','eslint.config.js','components.json','index.html','.nvmrc','package-lock.json']
for f in requiredFiles:
  assert fileExists('web/' + f)

requiredSrcPaths = ['main.tsx','App.tsx','globals.css','vite-env.d.ts','lib/utils.ts','routes/index.tsx','routes/not-found.tsx','components/ui/button.tsx']
for p in requiredSrcPaths:
  assert fileExists('web/src/' + p)
